// SPDX-License-Identifier: MIT

pragma solidity ^0.8.0;

contract System_for_booking {

    enum Status {
        Unrented,
        Rented
    }

    struct Resource {
        uint id;
        string name;
        address owner;
        bool isActive;
    }

    struct Booking {
        uint256 id;
        uint256 resourceId;
        address user;
        uint256 startDate;
        uint256 endDate;
        uint256 status;
    }

    mapping (uint256 => Resource) public resources;
    uint256 resourceCount = 0;

    mapping (uint256 => Booking) public bookings;
    uint256 bookingCount = 0;

    Booking[] public bookingsArray;

    address public owner;

    constructor() {
        owner = msg.sender;
    }

    function addResource (string calldata name) public {
        require(owner == msg.sender, "You not owner");
        require(bytes(name).length > 0, "Empty name");

        resources[resourceCount] = Resource({
            id: resourceCount,
            name: name,
            owner: msg.sender,
            isActive: true
        });

        resourceCount++;
    }

    function deactivationResource(uint256 resourceId) public {
        require(owner == msg.sender, "Only owner can deactivate");

        resources[resourceId].isActive = false;
    }

    function Orented(uint256 resourceId, uint256 daysBooking) public {
        require(resources[resourceId].isActive, "This resource is not active");
        require(daysBooking > 0, "Invalid value");
    
        Booking memory newBooking = Booking({
            id: bookingCount,
            resourceId: resourceId,
            user: msg.sender,
            startDate: block.timestamp,
            endDate: block.timestamp + daysBooking * 1 days,
            status: uint256(Status.Rented)
        });

        bookings[bookingCount] = newBooking;
        bookingsArray.push(newBooking);
        bookingCount++;
    }

    function CancelOrend(uint256 bookingId) external  {
        require(bookings[bookingId].user == msg.sender, "You can't cancel this booking");

        bookings[bookingId].status = uint256(Status.Unrented);
        bookings[bookingId].startDate = 0;
        bookings[bookingId].endDate = 0;
    }

    function history() public view returns(Booking[] memory) {
        require(bookingCount > 0 , "Booking empty");

        return bookingsArray;
    }

    function getNumber(uint256 first, uint256 second) public pure returns(uint256) {
        return first + second;
    }
}
